import{_ as o,o as t,c as a,a3 as e}from"./chunks/framework.DACwFHq9.js";const h=JSON.parse('{"title":"执行监控与调试","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/tool-calling/execution-debug.md","filePath":"user-guide/tools/llm-chat/tool-calling/execution-debug.md","lastUpdated":1778239080000}'),r={name:"user-guide/tools/llm-chat/tool-calling/execution-debug.md"};function i(s,l,n,g,c,u){return t(),a("div",null,[...l[0]||(l[0]=[e('<h1 id="执行监控与调试" tabindex="-1">执行监控与调试 <a class="header-anchor" href="#执行监控与调试" aria-label="Permalink to &quot;执行监控与调试&quot;">​</a></h1><p>工具调用并非黑盒过程，系统提供了丰富的 UI 反馈和调试信息，帮助用户追踪执行状态。</p><h2 id="消息组件-toolcallmessage" tabindex="-1">消息组件：ToolCallMessage <a class="header-anchor" href="#消息组件-toolcallmessage" aria-label="Permalink to &quot;消息组件：ToolCallMessage&quot;">​</a></h2><p>工具调用的请求和结果会以特殊的“工具消息”形式展示在对话流中：</p><ul><li><strong>状态标识</strong>：通过侧边栏颜色和图标识别状态（执行中、成功、失败、待审批、已取消）。</li><li><strong>参数折叠</strong>：默认折叠复杂的输入参数 JSON，点击可展开查看。</li><li><strong>JSON 美化</strong>：系统会自动美化工具返回的 JSON 数据，并限制缩进深度（最多 4 层），确保长数据不会撑破界面。</li><li><strong>性能统计</strong>：实时显示每个工具调用的执行耗时（ms）。</li></ul><h2 id="异步任务集成" tabindex="-1">异步任务集成 <a class="header-anchor" href="#异步任务集成" aria-label="Permalink to &quot;异步任务集成&quot;">​</a></h2><p>对于耗时较长的操作（如视频转码、大规模文件扫描），工具可能会创建一个“异步任务”：</p><ul><li><strong>进度追踪</strong>：消息块内会直接嵌入进度条和实时状态文字。</li><li><strong>交互控制</strong>：用户可以直接在消息内点击“取消任务”或“重试任务”。</li><li><strong>轮询机制</strong>：系统会自动轮询任务状态，并在完成后自动更新消息内容。</li></ul><h2 id="迭代控制" tabindex="-1">迭代控制 <a class="header-anchor" href="#迭代控制" aria-label="Permalink to &quot;迭代控制&quot;">​</a></h2><p>为了防止模型陷入“循环调用”或“过度调用”，系统实现了以下限制：</p><ul><li><strong>最大迭代次数 (maxIterations)</strong>：单次用户请求引发的工具链式调用次数上限。</li><li><strong>并行执行 (parallelExecution)</strong>：如果模型一次性请求了多个工具，系统支持并行执行以缩短等待时间。</li></ul><h2 id="调试建议" tabindex="-1">调试建议 <a class="header-anchor" href="#调试建议" aria-label="Permalink to &quot;调试建议&quot;">​</a></h2><p>如果工具调用不符合预期，可以检查以下几点：</p><ol><li><strong>参数对齐</strong>：在消息组件中展开参数，确认模型是否传错了字段或格式。</li><li><strong>上下文长度</strong>：检查工具返回的结果是否过大，导致后续生成的上下文被截断。</li><li><strong>角色转换</strong>：如果模型无法理解工具返回的结果，尝试切换 <code>convertToolRoleToUser</code> 选项。</li></ol><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./">工具调用概览</a></li><li><a href="./tool-definition">工具定义与宏注入</a></li></ul>',17)])])}const p=o(r,[["render",i]]);export{h as __pageData,p as default};
